// รวมข้อมูลจาก Form + Shopee page
const formData = $('Form Trigger').first().json;
const shopeeHtml = $input.first().json.data || '';

let shopeeDescription = '';
let autoImage = '';

try {
  // พยายาม extract __NEXT_DATA__ จาก Shopee
  const match = shopeeHtml.match(/<script id="__NEXT_DATA__" type="application\/json">(.*?)<\/script>/);
  if (match) {
    const nextData = JSON.parse(match[1]);
    const item = nextData?.props?.pageProps?.initialData?.data?.productItem;
    if (item) {
      shopeeDescription = (item.description || '').substring(0, 800);
      autoImage = item.images?.[0]
        ? `https://down-th.img.susercontent.com/file/${item.images[0]}`
        : '';
    }
  }
} catch (e) {
  // ไม่สามารถ parse ได้ — ใช้ข้อมูลจาก Form อย่างเดียว
}

// ใช้รูปจาก Form ก่อน ถ้าไม่มีค่อย fallback ไป auto-extract
const featuredImage = (formData['รูปภาพสินค้า (URL)'] || '').trim() || autoImage || null;

return [{
  json: {
    productName: formData['ชื่อสินค้า'],
    price: formData['ราคา'] || '',
    category: formData['หมวดหมู่'],
    shopeeUrl: formData['Shopee URL'],
    affiliateUrl: formData['Affiliate URL'] || formData['Shopee URL'],
    additionalInfo: formData['จุดเด่น / รายละเอียดเพิ่มเติม'] || '',
    shopeeDescription,
    featuredImage,
  }
}];

